INSERT INTO properties (id, internal_name, name, type, area, bedrooms, bathrooms, max_guests, base_price_night, description) VALUES
('prop_01', 'Villa Al Narjes', 'فيلا النرجس', 'فيلا', 'النرجس', 4, 3, 8, 1200, 'فيلا فاخرة في حي النرجس الراقي بالرياض، تتميز بتصميم عصري أنيق مع مسبح خاص وتراس واسع يطل على حديقة خضراء. مثالية للعائلات والمجموعات الباحثة عن تجربة إقامة استثنائية.'),
('prop_02', 'Penthouse Olaya', 'بنتهاوس العليا', 'شقة', 'العليا', 3, 2, 6, 950, 'بنتهاوس فاخر في قلب العليا يوفر إطلالات بانورامية خلابة على أفق الرياض. مفروش بأحدث الأثاث مع مطبخ مجهز بالكامل ومناطق معيشة رحبة.'),
('prop_03', 'Studio Diplomatic', 'شقة الدبلوماسي', 'ستوديو', 'الدبلوماسي', 1, 1, 2, 420, 'ستوديو أنيق في الحي الدبلوماسي، يجمع بين الراحة والموقع المتميز. مثالي للمسافرين بمفردهم أو للأزواج الباحثين عن مكان هادئ وأنيق.'),
('prop_04', 'Malqa Suite', 'سويت الملقا', 'شقة', 'الملقا', 2, 2, 4, 680, 'سويت فسيح في حي الملقا الهادئ، يوفر بيئة مثالية للعائلات الصغيرة. تتميز بتصميم داخلي راقٍ مع جميع وسائل الراحة الحديثة.'),
('prop_05', 'Villa Yasmin', 'فيلا الياسمين', 'فيلا', 'الياسمين', 5, 4, 10, 1800, 'فيلا ملكية بخمس غرف نوم في الياسمين الفاخر، مع مسبح خاص وحديقة مشجرة وسطح أنيق. تجربة إقامة لا تُنسى للمناسبات الخاصة والعائلات الكبيرة.'),
('prop_06', 'Embassy District Apt', 'شقة حي السفارات', 'شقة', 'السفارات', 2, 2, 4, 720, 'شقة راقية في الحي الدبلوماسي بالقرب من السفارات والمراكز التجارية.'),
('prop_07', 'Al Wurud Studio', 'ستوديو الورود', 'ستوديو', 'الورود', 1, 1, 2, 380, 'ستوديو عصري في حي الورود، يقدم أسلوب حياة مريح وعملي للمسافرين.'),
('prop_08', 'Al Nakheel Penthouse', 'بنتهاوس النخيل', 'شقة', 'النخيل', 3, 2, 6, 880, 'بنتهاوس فخم في النخيل مع مسبح على السطح وإطلالة رائعة على المدينة.'),
('prop_09', 'Tahlia Premium', 'شقة التحلية', 'شقة', 'التحلية', 2, 2, 4, 750, 'شقة أنيقة على شارع التحلية الشهير، قريبة من أفضل المطاعم والمحلات.'),
('prop_10', 'Al Rawabi Villa', 'فيلا الروابي', 'فيلا', 'الروابي', 4, 3, 8, 1400, 'فيلا راقية في الروابي مع مسبح خاص وحديقة خضراء وتراس خارجي فسيح.'),
('prop_11', 'Qurtuba Suite', 'سويت قرطبة', 'شقة', 'قرطبة', 2, 2, 4, 620, 'سويت هادئ في حي قرطبة الراقي، يوفر راحة تامة وخصوصية مثالية.'),
('prop_12', 'Sulaimaniyah Studio', 'ستوديو السليمانية', 'ستوديو', 'السليمانية', 1, 1, 2, 400, 'ستوديو مريح في السليمانية، موقع مركزي ممتاز وأسعار تنافسية.')
